class Solution:
    def sumOfGoodNumbers(self, nums, k):
        n = len(nums)
        total = 0
        for i in range(n):
            neighbors = []
            if i - k >= 0:
                neighbors.append(nums[i - k])
            if i + k < n:
                neighbors.append(nums[i + k])
            if all(nums[i] > x for x in neighbors):
                total += nums[i]
        return total

