class Solution:
    def sumOfGoodNumbers(self, nums, k):
        n = len(nums)
        total = 0
        for i in range(n):
            good = True
            if i - k >= 0 and nums[i - k] >= nums[i]:
                good = False
            if good and i + k < n and nums[i + k] >= nums[i]:
                good = False
            if good:
                total += nums[i]
        return total

