var sumOfGoodNumbers = function(nums, k) {
    const n = nums.length;
    let total = 0;
    for (let i = 0; i < n; i++) {
        let good = true;
        if (i - k >= 0 && nums[i - k] >= nums[i]) good = false;
        if (good && i + k < n && nums[i + k] >= nums[i]) good = false;
        if (good) total += nums[i];
    }
    return total;
